#include <iostream>
#include <string>

template <typename T, int N>
class FixedBuffer {
    T data_[N]{};
    int count_{0};
public:
    void push(T v) {
        data_[count_++] = v;
    }
    T get(int i) const {
        return data_[i];
    }
    int size() const { return count_; }
    int cap()  const { return N; }
};

int main() {
    FixedBuffer<int, 5> buf;
    int q{};
    std::cin >> q;
    for (int i = 0; i < q; ++i) {
        std::string op;
        std::cin >> op;
        if (op == "push") {
            int v{};
            std::cin >> v;
            buf.push(v);
        } else if (op == "size") {
            std::cout << buf.size() << "\n";
        } else if (op == "get") {
            int idx{};
            std::cin >> idx;
            std::cout << buf.get(idx) << "\n";
        } else if (op == "cap") {
            std::cout << buf.cap() << "\n";
        }
    }
    return 0;
}

