#include <iostream>

template <typename T>
class Snapshot {
    T data_;
public:
    explicit Snapshot(T v) : data_{v} {}
    T value() const { return data_; }
};

template <typename T>
class Snapshot<T*> {
    T copy_;
public:
    explicit Snapshot(T* p) : copy_{*p} {}
    T value() const { return copy_; }
};

int main() {
    int x = 42;
    Snapshot<int>  a{x};
    Snapshot<int*> b{&x};
    x = 99;
    std::cout << a.value() << "\n";
    std::cout << b.value() << "\n";
    return 0;
}
